DROP TABLE IF EXISTS TEMP_PSP_BANK_ACCOUNT CASCADE;

--------------------------------------------------------
-- Create temp table                                  --
--------------------------------------------------------

CREATE TABLE TEMP_PSP_BANK_ACCOUNT (LIKE PSP_BANK_ACCOUNT INCLUDING ALL) ;

