--------------------------------------------------------
-- Sychronize temp table and real table by            --
-- inserting, deleting, and updating as necessary     --
--------------------------------------------------------

INSERT INTO PSP_BANK_ACCOUNT
   (BANK_ACCOUNT_SEQ, VERSION, CREATED_DATE, MODIFIED_DATE, ACCOUNT_TYPE_CD, A_C_H_ACCOUNT_TYPE_CD, BANK_NAME, ROUTING_NUMBER, ACCOUNT_NUMBER_ENC, EFFECTIVE_DATE,EXPIRATION_DATE,CREATOR_ID )
SELECT
    BANK_ACCOUNT_SEQ, VERSION, CREATED_DATE, MODIFIED_DATE, ACCOUNT_TYPE_CD, A_C_H_ACCOUNT_TYPE_CD, BANK_NAME, ROUTING_NUMBER, ACCOUNT_NUMBER_ENC, EFFECTIVE_DATE,EXPIRATION_DATE,CREATOR_ID
FROM
   TEMP_PSP_BANK_ACCOUNT tt
WHERE
   tt.BANK_ACCOUNT_SEQ NOT IN (SELECT BANK_ACCOUNT_SEQ FROM PSP_BANK_ACCOUNT)

;

UPDATE PSP_BANK_ACCOUNT rt
SET ( VERSION, CREATED_DATE, MODIFIED_DATE, ACCOUNT_TYPE_CD, A_C_H_ACCOUNT_TYPE_CD, BANK_NAME, ROUTING_NUMBER, ACCOUNT_NUMBER_ENC, EFFECTIVE_DATE, EXPIRATION_DATE, CREATOR_ID) =
(SELECT  tt.VERSION, tt.CREATED_DATE, tt.MODIFIED_DATE, tt.ACCOUNT_TYPE_CD, tt.A_C_H_ACCOUNT_TYPE_CD, tt.BANK_NAME, tt.ROUTING_NUMBER, tt.ACCOUNT_NUMBER_ENC, tt.EFFECTIVE_DATE, tt.EXPIRATION_DATE,tt.CREATOR_ID
FROM TEMP_PSP_BANK_ACCOUNT tt WHERE tt.BANK_ACCOUNT_SEQ = rt.BANK_ACCOUNT_SEQ)
WHERE rt.BANK_ACCOUNT_SEQ IN (SELECT BANK_ACCOUNT_SEQ FROM TEMP_PSP_BANK_ACCOUNT)
;



